function Badge({children,tone='slate',title}:{children:any;tone?:string;title?:string}){const tones:any={green:'app-badge-green',red:'app-badge-red',yellow:'app-badge-yellow',blue:'app-badge-blue',purple:'app-badge-purple',slate:'app-badge-slate'};return <span title={title} className={(tones[tone]||tones.slate)+' app-badge inline-flex max-w-full rounded-full px-2 py-0.5 text-[11px] font-semibold tracking-tight break-words'}>{children||'—'}</span>}
function displayJobTitle(value?:string|null){const text=(value||'').replace(/\s*[-–—,;:]*\s*\(?\s*[mwfdx](?:\s*\/\s*[mwfdx]){1,3}\s*\)?\s*$/i,'').replace(/\s+/g,' ').trim();return text||value||'—'}
function locationLabel(value?:string|null){const title=(value||'').trim();if(!title)return {label:'—',title:''};return /^(wien|vienna)\b/i.test(title)?{label:'Vienna',title}:{label:title,title}}
function locationLabels(value?:string|null){const raw=(value||'').trim();if(!raw)return [locationLabel(raw)];const parts=raw.split(/\s*(?:[,;]|\s+\/\s+)\s*/).map(x=>x.trim()).filter(Boolean).filter(x=>! /^(at|austria|österreich)$/i.test(x));const items=(parts.length?parts:[raw]).map(locationLabel);const seen=new Set<string>();return items.filter(x=>{const key=x.label.toLowerCase();if(seen.has(key))return false;seen.add(key);return true})}
function LocationBadges({value,tones={},onToggle}:{value?:string|null;tones?:Record<string,string>;onToggle?:(label:string)=>void}){return <>{locationLabels(value).map((loc,i)=><button key={i} type="button" title={loc.title||'Click to cycle badge color'} onClick={e=>{e.stopPropagation();onToggle?.(loc.label)}} className="bg-transparent p-0"><Badge tone={tones[loc.label]||'slate'} title={loc.title}>{loc.label}</Badge></button>)}</>}
const statusTone=(s:string)=>({to_apply:'blue',applied:'purple',interview:'green',rejected:'red',skipped:'yellow',archived:'slate'} as any)[s]||'slate';
const priorityTone=(p?:string)=>p==='high'?'red':p==='medium'?'yellow':p==='low'?'slate':'slate';
const recTone=(r?:string)=>r==='apply'?'green':r==='maybe'?'yellow':r==='skip'?'red':'slate';
const scoreTone=(n?:number)=>n===undefined?'slate':n>=80?'green':n>=60?'yellow':'red';
function hrefFor(raw?:string){let v=(raw||'').trim(); if(!v)return ''; if(v.startsWith('http://')||v.startsWith('https://'))return v; if(v.startsWith('https-')||v.startsWith('http-')){const [scheme,...rest]=v.split('-'); const host=rest.shift(); if(host&&host.includes('.'))return `${scheme}://${host}/${rest.join('/')}`} if(v.includes('.')&&!v.includes(' '))return 'https://'+v; return v}
function daysSince(date?:string|null){if(!date)return null; return Math.floor((Date.now()-new Date(date+'T00:00:00').getTime())/86400000)}
function isStaleStatus(j:Job){const d=daysSince(j.status_date); return (j.status==='applied'||j.status==='interview')&&d!==null&&d>21}
function statusNeedsDate(s?:string){return datedStatuses.includes(s||'')}
function addDays(date:string,days:number){const d=new Date(date+'T00:00:00');d.setDate(d.getDate()+days);return d.toISOString().slice(0,10)}
function daysUntil(date?:string|null){if(!date)return null; return Math.ceil((new Date(date+'T00:00:00').getTime()-Date.now())/86400000)}
function feedbackDays(j:Job){if(j.feedback_due_date)return daysUntil(j.feedback_due_date); const d=daysSince(j.status_date); return (j.status==='applied'||j.status==='interview')&&d!==null?21-d:null}
function FeedbackDueText({days,prefix=false}:{days:number|null;prefix?:boolean}){if(days===null)return <>{prefix?'Feedback ':''}—</>; if(days<0)return <span className="feedback-overdue">{prefix&&<span className="leading-none">Feedback</span>}<span className="leading-none">{Math.abs(days)}d</span><span className="leading-none">overdue</span></span>; return <>{prefix?'Feedback ':''}{days}d left</>}
function ApplicationPace({stats}:{stats:any}){const monthWeeks=Array.isArray(stats.month_week_applications)?stats.month_week_applications:[];const workdays=Array.isArray(stats.workday_applications)?stats.workday_applications:[];const weekMax=Math.max(1,...monthWeeks.map((w:any)=>Number(w.count)||0));const dayMax=Math.max(1,...workdays.map((d:any)=>Number(d.count)||0));const countLabel=(n:any)=>`${Number(n)||0} application${Number(n)===1?'':'s'}`;return <div className="premium-card p-4 md:col-span-3"><div className="mb-3 flex items-start justify-between gap-3"><div><div className="text-xs uppercase text-slate-500">Application pace</div><div className="text-2xl font-semibold">{stats.applications_this_week??0}<span className="ml-1 text-sm font-medium text-slate-500">this week</span></div></div><div className="text-right"><div className="text-xs uppercase text-slate-500">Per workday</div><div className="text-2xl font-semibold">{stats.applications_per_workday??0}</div></div></div>{monthWeeks.length>0&&<div className="mb-4"><div className="mb-1 text-[10px] font-semibold uppercase text-slate-500">Weeks this month</div><div className="grid gap-2" style={{gridTemplateColumns:`repeat(${monthWeeks.length},minmax(0,1fr))`}}>{monthWeeks.map((w:any)=><div key={w.start||w.label} className="min-w-0" title={`${w.label} (${w.range}): ${countLabel(w.count)}`}><div className="flex h-16 items-end"><div className="w-full rounded-t-lg bg-blue-500/80 shadow-sm" style={{height:`${Math.max(8,(Number(w.count)||0)/weekMax*100)}%`}}/></div><div className="mt-1 min-h-8 text-center leading-tight"><div className="truncate text-[10px] font-semibold text-slate-600">{w.label}</div><div className="truncate text-[10px] font-medium text-slate-500">{w.range}</div></div></div>)}</div></div>}{workdays.length>0&&<div><div className="mb-1 text-[10px] font-semibold uppercase text-slate-500">Month by workday</div><div className="grid h-20 items-end gap-1" style={{gridTemplateColumns:`repeat(${workdays.length},minmax(8px,1fr))`}}>{workdays.map((d:any)=><div key={d.date||d.label} className="flex h-full min-w-0 flex-col justify-end gap-1" title={`${d.date||d.label}: ${countLabel(d.count)}`}><div className="rounded-t-md bg-blue-500/80 shadow-sm" style={{height:`${Math.max(8,(Number(d.count)||0)/dayMax*100)}%`}}/><div className="truncate text-center text-[9px] font-medium text-slate-500">{d.label}</div></div>)}</div></div>}</div>}
const dashboardPanelIds=['application_pace','total','new_high_priority','active_applied','active_interviews','due_followups'];
const dashboardPanelLabels:Record<string,string>={total:'Total',new_high_priority:'New high priority',active_applied:'Active applied',active_interviews:'Active interviews',due_followups:'Due follow-ups',application_pace:'Application pace'};
