function JobForm({publicMode=false}:{publicMode?:boolean}){const nav=useNavigate();const draftKey=publicMode?'dachapply_public_submit_draft':'dachapply_add_job_draft';const[form,setForm]=useState<any>(()=>JSON.parse(localStorage.getItem(draftKey)||'null')||(publicMode?{...empty,submitted_by:'',submitter_reason:''}:empty));function set(v:any){setForm(v);localStorage.setItem(draftKey,JSON.stringify(v))}const[msg,setMsg]=useState('');const[err,setErr]=useState<any>(()=>JSON.parse(localStorage.getItem(draftKey+'_err')||'null'));const[duplicateActions,setDuplicateActions]=useState<any[]>(()=>JSON.parse(localStorage.getItem(draftKey+'_actions')||'[]'));const[loading,setLoading]=useState(false);const[advanced,setAdvanced]=useState(false);const linkDraftRef=useRef((form.url||'')+'\n'+(form.raw_description||''));useEffect(()=>{const now=(form.url||'')+'\n'+(form.raw_description||'');if(now!==linkDraftRef.current){linkDraftRef.current=now;setErr(null);setDuplicateActions([]);localStorage.removeItem(draftKey+'_err');localStorage.removeItem(draftKey+'_actions')}},[form.url,form.raw_description]);useEffect(()=>{err?localStorage.setItem(draftKey+'_err',JSON.stringify(err)):localStorage.removeItem(draftKey+'_err')},[err]);useEffect(()=>{duplicateActions.length?localStorage.setItem(draftKey+'_actions',JSON.stringify(duplicateActions)):localStorage.removeItem(draftKey+'_actions')},[duplicateActions]);async function submitWith(extra:any={}){setErr(null);setMsg('');setLoading(true);const incoming=extra.duplicate_actions||[];const merged=[...duplicateActions.filter((a:any)=>!incoming.some((b:any)=>b.index===a.index)),...incoming];if(incoming.length)setDuplicateActions(merged);const body={...form,...extra,...((merged.length||extra.duplicate_actions)?{duplicate_actions:merged}:{})};try{const res=await api(publicMode?'/public/submit/':'/jobs/bulk-create/',{method:'POST',body});localStorage.removeItem(draftKey);localStorage.removeItem(draftKey+'_err');localStorage.removeItem(draftKey+'_actions');setDuplicateActions([]);setMsg(res?.count?`Saved ${res.count} job lead(s).`:'Saved successfully. Thank you!'); if(!publicMode&&!res?.count)nav('/')}catch(x:any){setErr(x)}finally{setLoading(false)}}async function sub(e:any){e.preventDefault();submitWith()}return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-2xl font-semibold">{publicMode?'Submit a job lead':'Add job'}</h1><p className="mb-5 text-slate-500">{publicMode?'Paste a link only, or add more details if you have them.':'Paste one or more job links in the URL field or notes. A URL or notes are enough.'}</p><form onSubmit={sub} className="grid gap-3">{publicMode&&<p className="rounded-lg bg-blue-50 p-3 text-sm text-blue-900">You can submit job links here. You will not get access to the private dashboard.</p>}<label className="text-sm font-medium">Job URL / links<textarea rows={Math.max(3,(form.url||'').split('\n').length,Math.ceil((form.url||'').length/80))} placeholder="One or more links, separated by spaces or new lines" value={form.url||''} onChange={e=>set({...form,url:e.target.value})}/></label><details open={advanced} onToggle={e=>setAdvanced((e.currentTarget as HTMLDetailsElement).open)}><summary className="cursor-pointer rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm font-medium text-slate-600">Advanced / optional details</summary><div className="mt-3 grid gap-3"><div className="grid gap-3 md:grid-cols-2"><input placeholder="Company (optional)" onChange={e=>set({...form,company:e.target.value})}/><input placeholder="Title (optional)" onChange={e=>set({...form,title:e.target.value})}/><input className="filter-input" placeholder="Location" onChange={e=>set({...form,location:e.target.value})}/><select onChange={e=>set({...form,work_mode:e.target.value})}>{workModes.map(x=><option key={x}>{x}</option>)}</select><input placeholder="Salary info" onChange={e=>set({...form,salary_info:e.target.value})}/><input placeholder="Language requirements" onChange={e=>set({...form,language_requirements:e.target.value})}/></div>{!publicMode&&<input placeholder="Source" onChange={e=>set({...form,source:e.target.value})}/>} {publicMode&&<><input placeholder="Your name" onChange={e=>set({...form,submitted_by:e.target.value})}/><textarea rows={Math.max(3,(form.submitter_reason||'').split('\n').length,Math.ceil((form.submitter_reason||'').length/80))} placeholder="Why do you think this fits?" value={form.submitter_reason||''} onChange={e=>set({...form,submitter_reason:e.target.value})}/></>}<textarea rows={Math.max(5,(form.raw_description||'').split('\n').length,Math.ceil((form.raw_description||'').length/80))} placeholder="Raw description / notes — you can paste multiple links here too" value={form.raw_description||''} onChange={e=>set({...form,raw_description:e.target.value})}/></div></details><p className="text-sm text-slate-500">Links like https-www.karriere.at-jobs-7794074 are accepted and normalized.</p><button disabled={loading}>{loading?'Saving…':'Submit'}</button>{msg&&<div className="rounded bg-green-50 p-3 text-green-800">{msg}</div>}{err?.type==='duplicate_conflicts'?<PublicDuplicateResolver error={err} onSubmit={submitWith} onCancel={()=>setErr(null)} publicMode={publicMode}/>:<ErrorBox error={err}/>}</form></div></main>}

function PublicDuplicateResolver({error,onSubmit,onCancel,publicMode}:{error:any;onSubmit:(x:any)=>void;onCancel:()=>void;publicMode:boolean}){const conflicts=error.conflicts||[];function pick(e:any,index:number,action:string){e.preventDefault();e.stopPropagation();onSubmit({duplicate_actions:[{index,action}]})}return <div className="rounded border border-yellow-200 bg-yellow-50 p-3 text-yellow-950"><b>{conflicts.length} duplicate link{conflicts.length===1?'':'s'} found.</b><p className="text-sm">These links already exist. {publicMode?'You can create duplicates or skip them.':'Choose what to do.'}</p><div className="mt-2 flex flex-wrap gap-2"><button type="button" onClick={()=>onSubmit({duplicate_strategy:'duplicate'})}>Duplicate all</button><button type="button" onClick={()=>onSubmit({duplicate_strategy:'skip'})}>Skip all</button>{!publicMode&&<button type="button" onClick={()=>onSubmit({duplicate_strategy:'override'})}>Override all</button>}<button type="button" className="bg-slate-500" onClick={onCancel}>Cancel</button></div>{conflicts.length>0&&<div className="mt-3 space-y-2">{conflicts.map((c:any)=><div key={c.index} className="flex items-center justify-between gap-3 rounded bg-white p-2"><a className="min-w-0 flex-1 break-all text-xs" href={hrefFor(c.url)} target="_blank" rel="noreferrer">{c.url}</a><span className="relative z-10 flex shrink-0 gap-1"><button type="button" title="Skip" className="btn-danger" onClick={e=>pick(e,c.index,'skip')}>✕ Skip</button><button type="button" title="Duplicate" className="btn-primary" onClick={e=>pick(e,c.index,'duplicate')}>⧉ Duplicate</button>{!publicMode&&<button type="button" title="Override" className="btn" onClick={e=>pick(e,c.index,'override')}>↻ Override</button>}</span></div>)}</div>}</div>}

function Detail(){const{id}=useParams();const[j,setJ]=useState<Job|null>(null);const[note,setNote]=useState('');const[loading,setLoading]=useState(true);const[err,setErr]=useState<any>(null);useEffect(()=>{api('/jobs/'+id+'/').then(setJ).catch(setErr).finally(()=>setLoading(false))},[id]);if(loading)return <Loading show/>;if(err)return <main className="p-6"><ErrorBox error={err}/></main>;if(!j)return <Empty>Job not found.</Empty>;let ev=j.latest_evaluation;return <main className="mx-auto max-w-5xl p-6"><Link to="/">← Dashboard</Link><div className="mt-4 rounded bg-white p-6 shadow-sm"><div className="flex flex-wrap items-start justify-between gap-4"><div><p className="text-sm text-slate-500">{j.company}</p><h1 className="text-3xl font-semibold">{j.url?<a href={hrefFor(j.url)} target="_blank" rel="noreferrer">{displayJobTitle(j.title)}</a>:displayJobTitle(j.title)}</h1><p className="mt-2 text-slate-600">{j.location||'Unknown location'} · {j.work_mode}</p></div><div className="flex gap-2"><Badge tone={statusTone(j.status)}>{j.status}</Badge>{ev&&<Badge tone={priorityTone(ev.priority)}>{ev.priority}</Badge>}{ev&&<Badge tone={recTone(ev.recommendation)}>{ev.recommendation}</Badge>}</div></div></div>{ev?<section className="mt-4 grid gap-4 md:grid-cols-3"><div className="rounded bg-white p-5 shadow-sm"><div className="text-sm text-slate-500">Fit score</div><div className="text-4xl font-semibold">{ev.fit_score}</div><p className="mt-2">{ev.summary}</p></div><div className="rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Main matches</h2><ul className="mt-2 list-disc pl-5 text-slate-700">{ev.main_match_reasons.map((x,i)=><li key={i}>{x}</li>)}</ul></div><div className="rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Main gaps</h2><ul className="mt-2 list-disc pl-5 text-slate-700">{ev.main_gaps.map((x,i)=><li key={i}>{x}</li>)}</ul></div><div className="rounded bg-white p-5 shadow-sm md:col-span-3"><h2 className="font-semibold">Next action</h2><p>{ev.next_action}</p><div className="mt-4 grid gap-4 md:grid-cols-3"><p><b>CV:</b> {ev.cv_adjustment_notes}</p><p><b>Interview:</b> {ev.interview_prep_notes}</p><p><b>Risk:</b> {ev.risk_notes}</p></div></div></section>:<div className="mt-4"><Empty>No evaluation yet. Generate a prompt from the Prompts page.</Empty></div>}<section className="mt-4 rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Description</h2><pre className="mt-2 whitespace-pre-wrap text-sm text-slate-700">{j.raw_description||'No description yet.'}</pre></section><section className="mt-4 rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Add note</h2><div className="mt-2 flex gap-2"><input placeholder="note" onChange={e=>setNote(e.target.value)}/><button onClick={()=>api('/jobs/'+id+'/notes/',{method:'POST',body:{note,note_type:'general'}})}>Save</button></div></section></main>}

function Prompts(){const[jobs,setJobs]=useState<Job[]>([]);const[ids,setIds]=useState<number[]>([]);const[p,setP]=useState('');const[links,setLinks]=useState('');const[loading,setLoading]=useState(true);const[err,setErr]=useState<any>(null);const[msg,setMsg]=useState('');useEffect(()=>{api('/jobs/').then(setJobs).catch(setErr).finally(()=>setLoading(false))},[]);const selected=useMemo(()=>jobs.filter(j=>ids.includes(j.id)),[jobs,ids]);async function gen(path:string,body:any){setErr(null);setMsg('');try{setP((await api(path,{method:'POST',body})).generated_prompt)}catch(e){setErr(e)}}return <main className="mx-auto max-w-6xl p-6"><h1 className="text-3xl font-semibold">Prompt generator</h1><p className="mb-4 text-slate-500">Prepare prompts manually, paste them into ChatGPT, then import JSON results.</p><ErrorBox error={err}/><section className="mb-4 rounded bg-white p-5 shadow-sm"><h2 className="text-xl font-semibold">Bulk links → details + evaluations</h2><textarea className="mt-3" rows={5} placeholder="Paste one job link per line" onChange={e=>setLinks(e.target.value)}/><button className="mt-3" onClick={()=>gen('/prompts/bulk-links/',{links})}>Generate Bulk Links Prompt</button></section><section className="grid gap-4 md:grid-cols-2"><div className="rounded bg-white p-5 shadow-sm"><h2 className="mb-3 text-xl font-semibold">Select existing jobs</h2><Loading show={loading}/>{!loading&&jobs.length===0&&<Empty>No jobs yet.</Empty>}<div className="max-h-96 space-y-2 overflow-auto">{jobs.map(j=><label key={j.id} className="flex gap-3 rounded border p-3 hover:bg-slate-50"><input type="checkbox" checked={ids.includes(j.id)} onChange={e=>setIds(e.target.checked?[...ids,j.id]:ids.filter(x=>x!==j.id))}/><span><b>#{j.id} {j.company}</b><br/><span className="text-slate-600">{displayJobTitle(j.title)}</span></span></label>)}</div><div className="mt-4 flex flex-wrap gap-2"><button disabled={!ids.length} onClick={()=>gen('/prompts/generate/',{job_ids:ids})}>Generate Evaluation Prompt</button><button disabled={!ids.length} onClick={()=>gen('/prompts/enrich/',{job_ids:ids})}>Generate Missing Details Prompt</button></div></div><div className="rounded bg-white p-5 shadow-sm"><h2 className="mb-3 text-xl font-semibold">Selected preview</h2>{selected.length===0?<p className="text-slate-500">No jobs selected.</p>:selected.map(j=><div key={j.id} className="mb-2 rounded bg-slate-50 p-3"><b>#{j.id} {j.company}</b><div>{displayJobTitle(j.title)}</div><div className="text-xs text-slate-500">{j.location} · {j.work_mode} · {j.url}</div></div>)}</div></section><section className="mt-4 rounded bg-white p-5 shadow-sm"><div className="mb-2 flex items-center justify-between"><h2 className="text-xl font-semibold">Generated prompt</h2><button disabled={!p} onClick={async()=>{await navigator.clipboard.writeText(p);setMsg('Copied to clipboard')}}>Copy to clipboard</button></div>{msg&&<div className="mb-2 rounded bg-green-50 p-2 text-green-800">{msg}</div>}<textarea rows={20} value={p} onChange={e=>setP(e.target.value)} placeholder="Generated prompt appears here…"/></section></main>}

function DuplicateResolver({error,jsonText,onDone}:{error:any;jsonText:string;onDone:(r:any)=>void}){const[actions,setActions]=useState<Record<number,string>>({});if(error?.type!=='duplicate_conflicts'&&error?.type!=='evaluation_conflicts')return <ErrorBox error={error}/>;async function submit(strategy?:string){const data=JSON.parse(jsonText);if(strategy)data.duplicate_strategy=strategy;else data.duplicate_actions=error.conflicts.map((c:any)=>({index:c.index,action:actions[c.index]||'skip'}));const res=await api('/evaluations/import/',{method:'POST',body:{json:JSON.stringify(data)}});onDone(res)}return <div className="rounded border border-yellow-200 bg-yellow-50 p-4 text-yellow-950"><h3 className="font-semibold">{error.type==='evaluation_conflicts'?'Existing evaluations found':'Duplicate jobs found'}</h3><p className="mb-3 text-sm">{error.type==='evaluation_conflicts'?'Some selected jobs already have evaluations. Choose whether to override, duplicate, skip, or abort.':'Some imported jobs already exist. Choose one action for all jobs, or decide per job.'}</p><div className="mb-3 flex flex-wrap gap-2"><button onClick={()=>submit('override')}>Override all</button><button onClick={()=>submit('duplicate')}>Duplicate all</button><button onClick={()=>submit('skip')}>Skip all</button><button className="bg-slate-500" onClick={()=>onDone({ok:false,aborted:true,message:'Import aborted'})}>Abort</button></div><div className="space-y-2">{error.conflicts.map((c:any)=><div key={c.index} className="rounded bg-white p-3"><div className="font-medium">{error.type==='evaluation_conflicts'?`Job #${c.job_id} already has an evaluation`:`Incoming: ${c.incoming.company} — ${c.incoming.title}`}</div>{c.url&&<div className="text-xs text-slate-600">URL: {c.url}</div>}<div className="text-xs text-slate-600">Existing: {c.existing_jobs?c.existing_jobs.map((j:any)=>`#${j.id} ${j.company} — ${displayJobTitle(j.title)}`).join('; '):c.existing_evaluations?.map((ev:any)=>`#${ev.id} ${ev.fit_score}% ${ev.priority} ${ev.recommendation}`).join('; ')}</div><select className="mt-2 max-w-xs" value={actions[c.index]||'skip'} onChange={e=>setActions({...actions,[c.index]:e.target.value})}><option value="skip">Skip this job</option><option value="override">Override existing</option><option value="duplicate">{error.type==='evaluation_conflicts'?'Add another evaluation':'Create duplicate with (1)'}</option></select></div>)}</div><button className="mt-3" onClick={()=>submit()}>Apply per-job choices</button></div>}

function ImportEval(){const[t,setT]=useState('');const[r,setR]=useState<any>(null);const[err,setErr]=useState<any>(null);const[loading,setLoading]=useState(false);async function submit(){setLoading(true);setErr(null);setR(null);try{setR(await api('/evaluations/import/',{method:'POST',body:{json:t}}))}catch(e){setErr(e)}finally{setLoading(false)}}const importedJobs=(r?.imported_jobs||r?.jobs||[]).filter((j:any)=>j.job_id);const jobsFound=r?.jobs_found??importedJobs.length;return <main className="mx-auto max-w-5xl p-6"><h1 className="text-3xl font-semibold">Import ChatGPT JSON</h1><p className="mb-4 text-slate-500">Paste evaluation JSON, job_updates JSON, or bulk jobs JSON.</p><textarea rows={18} placeholder="Paste JSON here" onChange={e=>setT(e.target.value)} /><button className="mt-3" disabled={loading||!t.trim()} onClick={submit}>{loading?'Importing…':'Validate and Import'}</button>{err&&<div className="mt-4"><h2 className="font-semibold text-red-700">Validation errors</h2><DuplicateResolver error={err} jsonText={t} onDone={(res:any)=>{setErr(null);setR(res)}}/></div>}{r&&<div className="mt-4 rounded bg-green-50 p-4 text-green-900"><h2 className="font-semibold">Import successful</h2>{r.type==='jobs'?<><p>{jobsFound} job{jobsFound===1?'':'s'} found and imported.</p>{importedJobs.length>0&&<ol className="mt-3 list-decimal space-y-1 pl-5">{importedJobs.map((j:any)=><li key={j.job_id}><b>{j.company||'Unknown company'}</b> - {displayJobTitle(j.title)||'Untitled role'} position</li>)}</ol>}</>:<><p>Imported {r.count??r.created_ids?.length??0} evaluation{(r.count??r.created_ids?.length??0)===1?'':'s'}.</p>{r.created_ids&&<p className="mt-2">Evaluation IDs: {r.created_ids.join(', ')}</p>}</>}</div>}</main>}

function Followups(){const[fs,setFs]=useState<FollowUp[]>([]);const[loading,setLoading]=useState(true);const[err,setErr]=useState<any>(null);async function load(){api('/followups/').then(setFs).catch(setErr).finally(()=>setLoading(false))}useEffect(()=>{load()},[]);let today=new Date().toISOString().slice(0,10);return <main className="mx-auto max-w-4xl p-6"><h1 className="text-3xl font-semibold">Follow-ups</h1><ErrorBox error={err}/><Loading show={loading}/>{!loading&&fs.length===0&&<Empty>No follow-ups yet.</Empty>}{fs.map(f=><div key={f.id} className={(f.follow_up_date<today&&!f.completed?'border-red-200 bg-red-50':'bg-white')+' my-2 rounded border p-4 shadow-sm'}><b>{f.follow_up_date}</b> {f.company} — {f.title}<p>{f.reason}</p>{!f.completed&&<button onClick={async()=>{await api('/followups/'+f.id+'/',{method:'PATCH',body:{completed:true}});load()}}>Mark completed</button>}</div>)}</main>}
function Export(){
  const[file,setFile]=useState<File|null>(null),[summary,setSummary]=useState<any>(null),[err,setErr]=useState<any>(null),[loading,setLoading]=useState(false),[dragging,setDragging]=useState(false),[open,setOpen]=useState<string|null>(null);
  const fileInputRef=useRef<HTMLInputElement|null>(null);
  function csrf(){return document.cookie.split('; ').find(r=>r.startsWith('csrftoken='))?.split('=')[1]}
  function preferences(){const prefs:any={theme:localStorage.getItem('dachapply_theme')||'light',hidden_columns:JSON.parse(localStorage.getItem('dachapply_hidden_cols')||'[]'),skill_overrides:JSON.parse(localStorage.getItem('dachapply_skill_overrides')||'{}'),work_mode_tones:JSON.parse(localStorage.getItem('dachapply_work_mode_tones')||'{}'),location_tones:JSON.parse(localStorage.getItem('dachapply_location_tones')||'{}')};for(let i=0;i<localStorage.length;i++){const key=localStorage.key(i)||'';if(key.startsWith('dachapply_')&&key!=='dachapply_user')prefs[key]=localStorage.getItem(key)}return prefs}
  function applyPreferences(prefs:any){if(!prefs||typeof prefs!=='object')return false;if(typeof prefs.theme==='string')localStorage.setItem('dachapply_theme',prefs.theme);if(Array.isArray(prefs.hidden_columns))localStorage.setItem('dachapply_hidden_cols',JSON.stringify(prefs.hidden_columns));if(prefs.skill_overrides&&typeof prefs.skill_overrides==='object')localStorage.setItem('dachapply_skill_overrides',JSON.stringify(prefs.skill_overrides));if(prefs.work_mode_tones&&typeof prefs.work_mode_tones==='object')localStorage.setItem('dachapply_work_mode_tones',JSON.stringify(prefs.work_mode_tones));if(prefs.location_tones&&typeof prefs.location_tones==='object')localStorage.setItem('dachapply_location_tones',JSON.stringify(prefs.location_tones));Object.entries(prefs).forEach(([k,v])=>{if(k.startsWith('dachapply_')&&k!=='dachapply_user')localStorage.setItem(k,String(v))});return true}
  function downloadBlob(blob:Blob,name:string){const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();URL.revokeObjectURL(a.href)}
  async function importFile(f?:File|null,strategy?:string){setErr(null);setSummary(null);if(!f)return;const name=f.name.toLowerCase();if(!name.endsWith('.json')&&!name.endsWith('.csv')&&!name.endsWith('.xlsx')){setFile(null);setErr('Please choose a JSON, CSV, or XLSX export file.');return}setFile(f);setLoading(true);try{let parsed:any=null;let importedPrefs:any=null;if(name.endsWith('.json')){try{parsed=JSON.parse(await f.text());importedPrefs=parsed.frontend_preferences||parsed.preferences}catch{}}const hasBackend=!!(parsed?.schema_version&&parsed?.app&&parsed?.data);if(name.endsWith('.json')&&importedPrefs&&!hasBackend){const ok=applyPreferences(importedPrefs);setSummary({created:{},updated:{},skipped:{},errors:[],preferences:ok?'imported':'none'});return}const body=new FormData();body.append('file',f);if(strategy)body.append('duplicate_strategy',strategy);const headers:any={};const token=csrf();if(token)headers['X-CSRFToken']=token;const res=await fetch('/api/import/',{method:'POST',credentials:'include',headers,body});const text=await res.text();const data=text?JSON.parse(text):{};if(!res.ok){if(data?.type==='import_conflicts')setSummary(data);else throw data;return}const prefs=data.frontend_preferences||importedPrefs;const ok=applyPreferences(prefs);setSummary(ok?{...data,preferences:'imported'}:data)}catch(e){setErr(e)}finally{setLoading(false);if(fileInputRef.current)fileInputRef.current.value=''}}
  async function exportKind(kind:'jobs'|'preferences'|'full',type:'json'|'csv'|'xlsx'){setErr(null);setOpen(null);try{const token=csrf();const headers:any={'Content-Type':'application/json'};if(token)headers['X-CSRFToken']=token;const res=await fetch('/api/export/',{method:'POST',credentials:'include',headers,body:JSON.stringify({kind,type,preferences:preferences()})});if(!res.ok)throw {detail:await res.text()};downloadBlob(await res.blob(),`dachapply-${kind}-${new Date().toISOString().slice(0,10)}.${type}`)}catch(e){setErr(e)}}
  function ExportChoice({id,label,icon}:{id:'jobs'|'preferences'|'full';label:string;icon:string}){return <span className="relative" onMouseEnter={()=>setOpen(id)} onMouseLeave={()=>setOpen(null)}><button className="btn-primary min-w-36 justify-center" onClick={()=>setOpen(open===id?null:id)} title={`${label}: choose JSON, CSV, or XLSX`}><span className="mr-1">{icon}</span>{label}</button>{open===id&&<div className="absolute left-0 top-full z-30 flex gap-1 rounded-2xl border border-slate-200 bg-white/95 p-2 text-slate-900 shadow-2xl ring-1 ring-slate-900/5 backdrop-blur"><button className="btn" onClick={()=>exportKind(id,'json')}>JSON</button><button className="btn" onClick={()=>exportKind(id,'csv')}>CSV</button><button className="btn" onClick={()=>exportKind(id,'xlsx')}>XLSX</button></div>}</span>}
  return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-3xl font-semibold">Data export / import</h1><p className="mb-5 text-slate-500">Export jobs, preferences, or both. Hover or click an option to choose JSON, CSV, or XLSX. Import automatically detects what the file contains.</p><section className="mb-6 rounded border p-4"><h2 className="mb-3 text-xl font-semibold">Export</h2><div className="flex flex-wrap gap-3"><ExportChoice id="jobs" label="Jobs" icon="💼"/><ExportChoice id="preferences" label="Preferences" icon="⚙"/><ExportChoice id="full" label="Everything" icon="⬇"/></div></section><section className="rounded border p-4"><h2 className="mb-2 text-xl font-semibold">Import</h2><div role="button" tabIndex={0} onClick={()=>!loading&&fileInputRef.current?.click()} onKeyDown={e=>{if((e.key==='Enter'||e.key===' ')&&!loading){e.preventDefault();fileInputRef.current?.click()}}} onMouseEnter={()=>setDragging(true)} onMouseLeave={()=>setDragging(false)} onDragEnter={e=>{e.preventDefault();setDragging(true)}} onDragOver={e=>{e.preventDefault();setDragging(true)}} onDragLeave={e=>{e.preventDefault();setDragging(false)}} onDrop={e=>{e.preventDefault();setDragging(false);importFile(e.dataTransfer.files?.[0])}} className={(dragging?'scale-[1.01] border-blue-500 bg-blue-50 text-blue-900 shadow-md':'border-slate-300 bg-slate-50 text-slate-600 shadow-sm')+' mb-3 cursor-pointer rounded-xl border-2 border-dashed p-6 text-center transition duration-150 hover:scale-[1.01] hover:border-blue-500 hover:bg-blue-50 hover:text-blue-900 hover:shadow-md focus:outline-none focus:ring-2 focus:ring-blue-500'}><p className="font-medium">Drop a JSON, CSV, or XLSX export here</p><p className="mt-1 text-sm">or click this area to choose and import a file.</p>{loading?<p className="mt-3 text-sm font-semibold">Importing...</p>:file&&<p className="mt-3 text-sm"><b>Selected:</b> {file.name}</p>}</div><input ref={fileInputRef} className="hidden" type="file" accept="application/json,.json,text/csv,.csv,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,.xlsx" onChange={e=>importFile(e.target.files?.[0]||null)}/>{summary?.type==='import_conflicts'&&<div className="mt-4 rounded border border-yellow-200 bg-yellow-50 p-4 text-yellow-950"><h3 className="font-semibold">Import conflicts found</h3><p className="mb-3 text-sm">Some imported records match existing records. Choose one action for all conflicts.</p><div className="mb-3 flex flex-wrap gap-2"><button onClick={()=>importFile(file,'override')}>Override all</button><button onClick={()=>importFile(file,'duplicate')}>Duplicate all</button><button onClick={()=>importFile(file,'skip')}>Skip all</button><button className="bg-slate-500" onClick={()=>setSummary(null)}>Abort</button></div><div className="space-y-2">{summary.conflicts?.map((c:any)=><div key={c.index} className="rounded bg-white p-3 text-sm"><div><b>{c.kind==='update'?'Existing record would be updated':'Duplicate URL'}</b></div><div>Incoming: {c.incoming?.company||'Unknown company'} - {c.incoming?.title||'Untitled role'}</div>{c.changed_fields&&<div className="text-xs text-slate-600">Changed fields: {c.changed_fields.join(', ')}</div>}<div className="text-xs text-slate-600">Existing: {c.existing_jobs?.map((j:any)=>`#${j.id} ${j.company} - ${displayJobTitle(j.title)}`).join('; ')}</div></div>)}</div></div>}{summary&&summary.type!=='import_conflicts'&&<div className="mt-4 rounded bg-green-50 p-4 text-green-900"><h3 className="font-semibold">Import summary</h3><pre className="mt-2 overflow-auto rounded bg-white p-3 text-xs">{JSON.stringify(summary,null,2)}</pre>{summary.preferences&&<p className="mt-2 text-sm">Preferences were imported. Refresh the page if theme or table settings do not update immediately.</p>}</div>}<div className="mt-4"><ErrorBox error={err}/></div></section></div></main>
}
export default function App(){return <><Nav/><Routes><Route path="/login" element={<Login/>}/><Route path="/reset-password/:uid/:token" element={<ResetPassword/>}/><Route path="/" element={<RequireAuth><Dashboard/></RequireAuth>}/><Route path="/add" element={<RequireAuth><JobForm/></RequireAuth>}/><Route path="/public-submit" element={<RequireAuth><JobForm publicMode/></RequireAuth>}/><Route path="/jobs/:id" element={<RequireAuth><Detail/></RequireAuth>}/><Route path="/prompts" element={<RequireAuth><Prompts/></RequireAuth>}/><Route path="/import" element={<RequireAuth><ImportEval/></RequireAuth>}/><Route path="/followups" element={<RequireAuth><Followups/></RequireAuth>}/><Route path="/export" element={<RequireAuth><Export/></RequireAuth>}/></Routes></>}
